export function matchRedirect(path) {
  if (REDIRECTS_MAP[path]) return REDIRECTS_MAP[path];
  if (REDIRECTS_MAP[path + "/"]) return REDIRECTS_MAP[path + "/"];
  if (path.endsWith("/") && REDIRECTS_MAP[path.slice(0, -1)]) return REDIRECTS_MAP[path.slice(0, -1)];
  return null;
}
